/**
 * NORMALIZADOR - COM CORREÇÃO DE VIRADA DE ANO
 */
let accountId = "";
let bankName = "";
let accountName = "";

try {
  const webData = $('Webhook').first().json.body;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
  accountName = webData.accountName || "Conta";
} catch (e) {
  bankName = "Banco";
}

const nomeContaCompleto = `${bankName} - ${accountName}`;

// 1. Extração da Referência Real (Âncora da Fatura)
// Padrão de fallback para o ano atual caso o PDF falhe
let anoRef = new Date().getFullYear(); 
let mesRef = new Date().getMonth(); 
let diaVencimento = 10;

try {
    const texto = $('Extract from File5').first().json.text;
    const matchVenc = texto.match(/Vencimento:\s*(\d{2})\/(\d{2})\/(\d{4})/i);
    if (matchVenc) {
        diaVencimento = parseInt(matchVenc[1]);
        mesRef = parseInt(matchVenc[2]) - 1; // Mês do vencimento (0-11)
        anoRef = parseInt(matchVenc[3]);     // Ano extraído do PDF
    }
} catch (e) {}

// A "Competência" da fatura (mês de consumo) é o mês anterior ao vencimento
let mesCompetencia = mesRef - 1; 
let anoCompetencia = anoRef;
if (mesCompetencia < 0) { 
    mesCompetencia = 11; 
    anoCompetencia--; 
}

let listaBruta = [];
try {
    const aiData = $('LLM Chain PDF4').first().json;
    listaBruta = aiData.output || (Array.isArray(aiData) ? aiData : []);
} catch (e) {}

const resultado = [];
listaBruta.forEach((item, index) => {
  const descOriginal = (item.t || "").toString().toUpperCase().trim();
  const valorOriginal = parseFloat(item.v) || 0;
  const sinal = item.s || "+";
  let valorFinal = (sinal === "-") ? Math.abs(valorOriginal) : -Math.abs(valorOriginal);

  // --- LÓGICA DE DATA CORRIGIDA ---
  let diaFinal = 1;
  let mesFinal = mesCompetencia;
  let anoFinal = anoCompetencia;

  if (item.d && item.d.includes('/')) {
    const partes = item.d.split('/');
    diaFinal = parseInt(partes[0]);
    let mesExtraido = parseInt(partes[1]) - 1;

    // Se a IA mandar ano com 2 dígitos (ex: 26), converte para 2026. Se não mandar, usa o ano da fatura.
    let anoExtraido = partes[2] ? 
        (partes[2].length === 2 ? 2000 + parseInt(partes[2]) : parseInt(partes[2])) : 
        anoRef;

    // --- NOVA TRAVA DE SANIDADE (RELATIVA) ---
    // Em vez de barrar 2026, calculamos a distância em meses entre a compra e o vencimento.
    // Isso permite viradas de ano (Dez/25 em fatura de Jan/26).
    const dataCompra = new Date(anoExtraido, mesExtraido, diaFinal);
    const dataVencimento = new Date(anoRef, mesRef, diaVencimento);

    // Calcula diferença total de meses
    const diffMeses = (anoExtraido * 12 + mesExtraido) - (anoRef * 12 + mesRef);

