/**
 * NORMALIZADOR OTIMIZADO PARA ESTRUTURA DE OUTPUT DA LLM
 */

// 1. DADOS DA CONTA
const webhook = $('Webhook').first().json.body;
const accountId = webhook.accountId || "";
const bankName = webhook.bankName || "Banco";
const userId = webhook.userId || "";

// 2. CAPTURA DOS ITENS (Furando a camada 'output')
const incomingData = $input.all();
let listaParaProcessar = [];

// A LLM Chain geralmente entrega como $json.output.output ou similar
if (incomingData[0].json.output && Array.isArray(incomingData[0].json.output.output)) {
  listaParaProcessar = incomingData[0].json.output.output;
} else if (Array.isArray(incomingData[0].json.output)) {
  listaParaProcessar = incomingData[0].json.output;
} else {
  listaParaProcessar = incomingData.map(i => i.json);
}

// 3. MAPEAMENTO REAL
return listaParaProcessar.map((data, index) => {

  // Tratamento de Valor
  let v = data.v !== undefined ? data.v : 0;
  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (data.s === "-") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);

  // Formatação de Data (DD/MM/YYYY -> YYYY-MM-DD)
  let dataF = data.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    // Assume DD/MM/YYYY
    dataF = `${p[2]}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}`;
  }

  return {
    json: {
      account_id: accountId,
      user_id: userId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: (data.t || "SEM DESCRICAO").toString().toUpperCase().trim(),
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno"].includes(data.c) ? "neutro" : "receita"),
      Categoria: data.c || "outros-gv",
      id_conciliacao: `${dataF}-${valorFinal}-${index}`
    }
  };
});

return $input.all().map(item => {
  const raw = item.json;

  // Criamos um objeto com todas as chaves em minúsculo para evitar erro de Case Sensitive
  const cleanRaw = {};
  Object.keys(raw).forEach(key => {
    cleanRaw[key.toLowerCase().trim()] = raw[key];
  });

  // Tenta pegar os campos ignorando maiúsculo/minúsculo
  const dataString = cleanRaw['data'];
  const lancamento = cleanRaw['lançamento'] || cleanRaw['lancamento'] || cleanRaw['descricao'] || "SEM DESCRIÇÃO";
  const valorNum = cleanRaw['valor'];

  // Se não achar a data, pula a linha
  if (!dataString || typeof dataString !== 'string') return null;

  const valorOriginal = parseFloat(valorNum);
  if (isNaN(valorOriginal)) return null; // Pula se o valor não for um número

  const sinal = valorOriginal > 0 ? '-' : '+';
  const valorAbsoluto = Math.abs(valorOriginal);

  // Trata a data (YYYY-MM-DD para DD/MM/YYYY)
  const partesData = dataString.split('-');
  if (partesData.length < 3) return null;

  const dataFormatada = `${partesData[2]}/${partesData[1]}/${partesData[0]}`;

  return {
    json: {
      d: dataFormatada,
      t: lancamento.toString().toUpperCase(),
      v: valorAbsoluto,
      s: sinal,
      c: null 
    }
  };
}).filter(i => i !== null);

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
