/**
 * NORMALIZADOR CORRIGIDO
 */

// 1. DADOS DA CONTA
const webhook = $('Webhook').first().json.body;
const accountId = webhook.accountId || "";
const bankName = webhook.bankName || "Banco";
const userId = webhook.userId || "";

// 2. CAPTURA DOS ITENS
const incomingData = $input.all();
let listaParaProcessar = [];

if (incomingData[0].json.output) {
  // Ajuste para pegar o output da Chain de forma segura
  const out = incomingData[0].json.output;
  listaParaProcessar = Array.isArray(out) ? out : (Array.isArray(out.output) ? out.output : [out]);
} else {
  listaParaProcessar = incomingData.map(i => i.json);
}

// 3. MAPEAMENTO REAL
return listaParaProcessar.map((data, index) => {

  // Tratamento de Valor - Mais robusto
  let v = data.v !== undefined ? data.v : 0;
  if (typeof v === 'string') {
    v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  }

  let valorBase = Math.abs(parseFloat(v)) || 0;
  let sinal = data.s;

  // Forçar sinal negativo se a categoria for de saída ou o sinal enviado for "-"
  // Isso blinda contra falhas da LLM em esquecer o sinal no campo 'v'
  let valorFinal;
  if (sinal === "-" || (typeof v === 'number' && v < 0)) {
    valorFinal = -valorBase;
  } else {
    valorFinal = valorBase;
  }

  // Formatação de Data (DD/MM/YYYY -> YYYY-MM-DD)
  let dataF = data.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    if (p[2] && p[2].length === 4) {
      dataF = `${p[2]}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}`;
    }
  }

  // Definição do Tipo baseada no VALOR FINAL
  let tipoFinal = "receita";
  if (valorFinal < 0) {
    tipoFinal = "despesa";
  } else if (["reembolsos", "estorno"].includes(data.c)) {
    tipoFinal = "neutro";
  }

  return {
    json: {
      account_id: accountId,
      user_id: userId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: (data.t || "SEM DESCRICAO").toString().toUpperCase().trim(),
      Valor: valorFinal,
      Tipo: tipoFinal,
      Categoria: data.c || "outros-gv",
      id_conciliacao: `${dataF}-${valorFinal}-${index}`
    }
  };
});

const finalResults = [];
const hoje = new Date();
hoje.setHours(12, 0, 0, 0);
const hojeIso = hoje.toISOString().split('T')[0];

function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// 1. Definição de variáveis globais com segurança
